proof_block:
// `det_block_running_thread_equal` compares the two post states on
//   - r1 == r2                          (unit, trivial)
//   - root_container                    (not pinned by the ensures)
//   - container_perms@                  Map<ContainerPtr, PointsTo<Container>>
//   - process_perms@                    Map<ProcPtr,      PointsTo<Process>>
//   - thread_perms@                     Map<ThreadPtr,    PointsTo<Thread>>
//   - endpoint_perms@                   Map<EndpointPtr,  PointsTo<Endpoint>>
//   - cpu_list@                         (not pinned by the ensures)
//
// The per-domain forall ensures use `post1_self_.get_X(_)` and
// `post2_self_.get_X(_)` as their (separate) triggers, so z3 never lines them
// up at a common key.  Manually instantiate each forall on both sides at the
// same key, with the trigger annotated explicitly, to derive pointwise value
// equality.  Finally use Map extensionality (`=~=`) to lift to the whole
// underlying perms maps.

let target_ep = pre_self_.get_thread(thread_ptr).endpoint_descriptors@[endpoint_index as int].unwrap();

// ---- Domain equalities (each side independently) ----
assert(post1_self_.proc_dom() =~= pre_self_.proc_dom());
assert(post2_self_.proc_dom() =~= pre_self_.proc_dom());
assert(post1_self_.container_dom() == pre_self_.container_dom());
assert(post2_self_.container_dom() == pre_self_.container_dom());
assert(post1_self_.thread_dom() == pre_self_.thread_dom());
assert(post2_self_.thread_dom() == pre_self_.thread_dom());
assert(post1_self_.endpoint_dom() == pre_self_.endpoint_dom());
assert(post2_self_.endpoint_dom() == pre_self_.endpoint_dom());

// ---- Domain equalities across the two posts (consequence of above) ----
assert((post1_self_.process_perms)@.dom() =~= (post2_self_.process_perms)@.dom());
assert((post1_self_.container_perms)@.dom() =~= (post2_self_.container_perms)@.dom());
assert((post1_self_.thread_perms)@.dom() =~= (post2_self_.thread_perms)@.dom());
assert((post1_self_.endpoint_perms)@.dom() =~= (post2_self_.endpoint_perms)@.dom());

// ---- Procs: pointwise value() equality at each key ----
// Annotate both `post1_self_.get_proc(p_ptr)` and `post2_self_.get_proc(p_ptr)`
// as triggers so the forall ensures on both runs fire on the same `p_ptr`.
assert forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr), post2_self_.get_proc(p_ptr)]
    pre_self_.proc_dom().contains(p_ptr) implies
    post1_self_.process_perms@[p_ptr] == post2_self_.process_perms@[p_ptr] by
{
    // Each ensures fires because we mention its trigger.
    assert(post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    assert(post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    // Bridge to the underlying PointsTo<Process>.
    assert(post1_self_.process_perms@[p_ptr].value() =~= pre_self_.process_perms@[p_ptr].value());
    assert(post2_self_.process_perms@[p_ptr].value() =~= pre_self_.process_perms@[p_ptr].value());
    assert(post1_self_.process_perms@[p_ptr].value() =~= post2_self_.process_perms@[p_ptr].value());
}

// ---- Containers: pointwise value() equality at each key ----
assert forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(c_ptr), post2_self_.get_container(c_ptr)]
    pre_self_.container_dom().contains(c_ptr) implies
    post1_self_.container_perms@[c_ptr] == post2_self_.container_perms@[c_ptr] by
{
    assert(post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
    assert(post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
    assert(post1_self_.container_perms@[c_ptr].value() =~= pre_self_.container_perms@[c_ptr].value());
    assert(post2_self_.container_perms@[c_ptr].value() =~= pre_self_.container_perms@[c_ptr].value());
    assert(post1_self_.container_perms@[c_ptr].value() =~= post2_self_.container_perms@[c_ptr].value());
}

// ---- Threads: pointwise value() equality at each key ----
// The ensures share the trigger `pre_self_.get_thread(t_ptr)`, so mentioning
// it once already fires both runs.  The target thread is also pinned by the
// other ensures (state, ipc_payload, endpoint_descriptors), so we case-split
// on `t_ptr == thread_ptr`.
assert forall|t_ptr: ThreadPtr|
    #![trigger post1_self_.thread_perms@[t_ptr], post2_self_.thread_perms@[t_ptr]]
    pre_self_.thread_dom().contains(t_ptr) implies
    post1_self_.thread_perms@[t_ptr] == post2_self_.thread_perms@[t_ptr] by
{
    if t_ptr == thread_ptr {
        // Both posts pin the target thread's three fields equally.
        assert(post1_self_.get_thread(thread_ptr).endpoint_descriptors
            =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors);
        assert(post2_self_.get_thread(thread_ptr).endpoint_descriptors
            =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors);
        assert(post1_self_.get_thread(thread_ptr).ipc_payload =~= ipc_payload);
        assert(post2_self_.get_thread(thread_ptr).ipc_payload =~= ipc_payload);
        assert(post1_self_.get_thread(thread_ptr).state == ThreadState::BLOCKED);
        assert(post2_self_.get_thread(thread_ptr).state == ThreadState::BLOCKED);
    } else {
        // Non-target threads are pinned to the pre value on both sides.
        assert(pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
        assert(pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
    }
    assert(post1_self_.thread_perms@[t_ptr].value() =~= post2_self_.thread_perms@[t_ptr].value());
}

// ---- Endpoints: pointwise value() equality at each key ----
assert forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr), post2_self_.get_endpoint(e_ptr)]
    pre_self_.endpoint_dom().contains(e_ptr) implies
    post1_self_.endpoint_perms@[e_ptr] == post2_self_.endpoint_perms@[e_ptr] by
{
    assert(post1_self_.endpoint_dom().contains(e_ptr));
    assert(post2_self_.endpoint_dom().contains(e_ptr));
    if e_ptr == target_ep {
        // Both posts pin queue_state, owning_threads, queue@ for the target endpoint.
        assert(post1_self_.get_endpoint(target_ep).queue_state
            == pre_self_.get_endpoint(target_ep).queue_state);
        assert(post2_self_.get_endpoint(target_ep).queue_state
            == pre_self_.get_endpoint(target_ep).queue_state);
        assert(post1_self_.get_endpoint(target_ep).owning_threads
            == pre_self_.get_endpoint(target_ep).owning_threads);
        assert(post2_self_.get_endpoint(target_ep).owning_threads
            == pre_self_.get_endpoint(target_ep).owning_threads);
        assert(post1_self_.get_endpoint(target_ep).queue@
            == pre_self_.get_endpoint(target_ep).queue@.push(thread_ptr));
        assert(post2_self_.get_endpoint(target_ep).queue@
            == pre_self_.get_endpoint(target_ep).queue@.push(thread_ptr));
    } else {
        assert(post1_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));
        assert(post2_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));
    }
    assert(post1_self_.endpoint_perms@[e_ptr].value() =~= post2_self_.endpoint_perms@[e_ptr].value());
}

// ---- Lift pointwise PointsTo equality to Map equality via extensionality ----
assert((post1_self_.process_perms)@   =~= (post2_self_.process_perms)@);
assert((post1_self_.container_perms)@ =~= (post2_self_.container_perms)@);
assert((post1_self_.thread_perms)@    =~= (post2_self_.thread_perms)@);
assert((post1_self_.endpoint_perms)@  =~= (post2_self_.endpoint_perms)@);

// ---- Return values are unit. ----
assert(r1 == r2);
